import { Test, TestingModule } from '@nestjs/testing';
import { getRepositoryToken } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { SyncService } from './sync.service';
import { UsaSpendingService } from './usa-spending.service';
import { OpenFemaService } from './openfema.service';
import { Agency } from '../agencies/agency.entity';
import { SpendingRecord } from '../spending/spending-record.entity';
import { GeoSpendingSnapshot } from '../geography/geo-spending-snapshot.entity';
import { DisasterFundingRecord } from '../disaster/disaster-funding-record.entity';
import { DisasterRecoveryRatio } from '../disaster/disaster-recovery-ratio.entity';
import { StateAggregationResult } from './openfema.service';

describe('SyncService', () => {
  let service: SyncService;
  let agencyRepo: Repository<Agency>;
  let spendingRepo: Repository<SpendingRecord>;
  let geoRepo: Repository<GeoSpendingSnapshot>;
  let disasterRepo: Repository<DisasterFundingRecord>;
  let ratioRepo: Repository<DisasterRecoveryRatio>;
  let usaService: UsaSpendingService;
  let femaService: OpenFemaService;

  interface TestCase {
    name: string;
    method: string;
    agencyFetchResult?: { status: string; agencies?: any[] };
    spendingFetchResult?: { status: string; rows?: any[]; total?: number };
    geoFetchResult?: { status: string; rows?: any[] };
    disasterFetchResult?: { status: string; rows?: any[] };
    femaFetchResult?: StateAggregationResult[];
    findOneReturns: Record<string, any>;
    expectedSaveCalls: { repoName: string; count: number }[];
    expectedRepoData?: Record<string, any[]>;
  }

  const testTable: TestCase[] = [
    {
      name: 'syncAgenciesAndSpending upserts a new agency',
      method: 'syncAgenciesAndSpending',
      agencyFetchResult: { status: 'success', agencies: [
        { id: 0, name: 'Test Agency', abbreviation: 'TA', toptierCode: 'ABC' }
      ]},
      findOneReturns: { Agency: null },
      expectedSaveCalls: [{ repoName: 'agency', count: 1 }],
      expectedRepoData: {
        agency: [{ name: 'Test Agency', toptierCode: 'ABC' }],
      },
    },
    {
      name: 'syncAgenciesAndSpending updates an existing agency',
      method: 'syncAgenciesAndSpending',
      agencyFetchResult: { status: 'success', agencies: [
        { id: 1, name: 'Updated Agency', abbreviation: 'UA', toptierCode: 'ABC' }
      ]},
      findOneReturns: {
        Agency: { id: 1, name: 'Old Agency', abbreviation: 'OA', toptierCode: 'ABC' }
      },
      expectedSaveCalls: [{ repoName: 'agency', count: 1 }],
      expectedRepoData: {
        agency: [{ name: 'Updated Agency', toptierCode: 'ABC' }],
      },
    },
    {
      name: 'syncAgenciesAndSpending upserts a new spending record',
      method: 'syncAgenciesAndSpending',
      agencyFetchResult: { status: 'not_found' },
      spendingFetchResult: { status: 'success', rows: [
        { id: 0, agencyId: 1, fiscalYear: 2024, quarter: 1, awardTypeLabel: 'Grant', awardTypeCodes: '', obligatedAmount: 1000, outlayAmount: 500, awardCount: 1 }
      ], total: 1},
      findOneReturns: { SpendingRecord: null },
      expectedSaveCalls: [{ repoName: 'spending', count: 1 }],
      expectedRepoData: {
        spending: [{ agencyId: 1, fiscalYear: 2024, obligatedAmount: 1000 }],
      },
    },
    {
      name: 'syncGeography upserts a new geo snapshot',
      method: 'syncGeography',
      geoFetchResult: { status: 'success', rows: [
        { id: 0, stateCode: 'CA', stateName: 'California', fiscalYear: 2024, agencyId: 1, scope: 'recipient', obligatedAmount: 5000, awardCount: 3, population: 1000, perCapita: 5 }
      ]},
      findOneReturns: { GeoSpendingSnapshot: null },
      expectedSaveCalls: [{ repoName: 'geo', count: 1 }],
      expectedRepoData: {
        geo: [{ stateCode: 'CA', fiscalYear: 2024 }],
      },
    },
    {
      name: 'syncDisaster upserts a new disaster funding record',
      method: 'syncDisaster',
      disasterFetchResult: { status: 'success', rows: [
        { id: 0, defGroup: 'JF-3038', defCodes: 'JF-3038', stateCode: 'CA', stateName: 'California', obligatedAmount: 10000, outlayAmount: 8000, awardCount: 5, perCapita: 0, population: 0 }
      ]},
      femaFetchResult: [],
      findOneReturns: { DisasterFundingRecord: null },
      expectedSaveCalls: [{ repoName: 'disaster', count: 1 }],
      expectedRepoData: {
        disaster: [{ defGroup: 'JF-3038', stateCode: 'CA' }],
      },
    },
    {
      name: 'syncDisaster stores recovery ratio when no federal spending exists for the state',
      method: 'syncDisaster',
      disasterFetchResult: { status: 'success', rows: [] },
      femaFetchResult: [
        { stateCode: 'CA', stateName: 'California', fiscalYear: 2024, femaObligatedCents: 5000, declarationCount: 2, dominantIncidentType: 'Wildfire' }
      ],
      findOneReturns: {},
      expectedSaveCalls: [{ repoName: 'ratio', count: 1 }],
      expectedRepoData: {
        ratio: [{ stateCode: 'CA', recoveryRatio: 0, fedSpendingObligated: 0, femaObligated: 5000 }],
      },
    },
    {
      name: 'syncDisaster aggregates federal spending per state and computes the recovery ratio',
      method: 'syncDisaster',
      disasterFetchResult: { status: 'success', rows: [
        { id: 0, defGroup: 'JF-3038', defCodes: 'JF-3038', stateCode: 'CA', stateName: 'California', obligatedAmount: 10000, outlayAmount: 8000, awardCount: 5, perCapita: 0, population: 0 }
      ]},
      femaFetchResult: [
        { stateCode: 'CA', stateName: 'California', fiscalYear: 2024, femaObligatedCents: 5000, declarationCount: 2, dominantIncidentType: 'Wildfire' }
      ],
      findOneReturns: { DisasterFundingRecord: null },
      expectedSaveCalls: [
        { repoName: 'disaster', count: 1 },
        { repoName: 'ratio', count: 1 },
      ],
      expectedRepoData: {
        disaster: [{ defGroup: 'JF-3038', stateCode: 'CA' }],
        ratio: [{ stateCode: 'CA', recoveryRatio: 2, fedSpendingObligated: 10000, femaObligated: 5000 }],
      },
    },
    {
      name: 'syncAll orchestrates all methods',
      method: 'syncAll',
      agencyFetchResult: { status: 'success', agencies: [
        { id: 0, name: 'Test Agency', abbreviation: 'TA', toptierCode: 'ABC' }
      ]},
      spendingFetchResult: { status: 'not_found' },
      geoFetchResult: { status: 'success', rows: [
        { id: 0, stateCode: 'CA', stateName: 'California', fiscalYear: 2024, agencyId: 1, scope: 'recipient', obligatedAmount: 5000, awardCount: 3, population: 1000, perCapita: 5 }
      ]},
      disasterFetchResult: { status: 'success', rows: [] },
      femaFetchResult: [
        { stateCode: 'CA', stateName: 'California', fiscalYear: 2024, femaObligatedCents: 5000, declarationCount: 2, dominantIncidentType: 'Wildfire' }
      ],
      findOneReturns: { Agency: null, GeoSpendingSnapshot: null },
      expectedSaveCalls: [
        { repoName: 'agency', count: 1 },
        { repoName: 'geo', count: 1 },
        { repoName: 'ratio', count: 1 },
      ],
      expectedRepoData: {
        agency: [{ name: 'Test Agency' }],
        geo: [{ stateCode: 'CA' }],
        ratio: [{ stateCode: 'CA' }],
      },
    },
  ];

  beforeEach(async () => {
    const mockAgencyRepo = { findOne: jest.fn(), save: jest.fn() };
    const mockSpendingRepo = { findOne: jest.fn(), save: jest.fn() };
    const mockGeoRepo = { findOne: jest.fn(), save: jest.fn() };
    const mockDisasterRepo = { findOne: jest.fn(), save: jest.fn() };
    const mockRatioRepo = { findOne: jest.fn(), save: jest.fn() };
    const mockUsaService = {
      fetchAgencies: jest.fn(),
      fetchSpendingByAgency: jest.fn(),
      fetchGeoSnapshots: jest.fn(),
      fetchDisasterSpending: jest.fn(),
    };
    const mockFemaService = {
      fetchDeclarationsByState: jest.fn(),
    };

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        SyncService,
        { provide: getRepositoryToken(Agency), useValue: mockAgencyRepo },
        { provide: getRepositoryToken(SpendingRecord), useValue: mockSpendingRepo },
        { provide: getRepositoryToken(GeoSpendingSnapshot), useValue: mockGeoRepo },
        { provide: getRepositoryToken(DisasterFundingRecord), useValue: mockDisasterRepo },
        { provide: getRepositoryToken(DisasterRecoveryRatio), useValue: mockRatioRepo },
        { provide: UsaSpendingService, useValue: mockUsaService },
        { provide: OpenFemaService, useValue: mockFemaService },
      ],
    }).compile();

    service = module.get<SyncService>(SyncService);
    agencyRepo = module.get(getRepositoryToken(Agency));
    spendingRepo = module.get(getRepositoryToken(SpendingRecord));
    geoRepo = module.get(getRepositoryToken(GeoSpendingSnapshot));
    disasterRepo = module.get(getRepositoryToken(DisasterFundingRecord));
    ratioRepo = module.get(getRepositoryToken(DisasterRecoveryRatio));
    usaService = module.get<UsaSpendingService>(UsaSpendingService);
    femaService = module.get<OpenFemaService>(OpenFemaService);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  it.each(testTable)('$name', async ({
    method,
    agencyFetchResult,
    spendingFetchResult,
    geoFetchResult,
    disasterFetchResult,
    femaFetchResult,
    findOneReturns,
    expectedSaveCalls,
    expectedRepoData,
  }) => {
    usaService.fetchAgencies.mockResolvedValue({ status: 'not_found' });
    usaService.fetchSpendingByAgency.mockResolvedValue({ status: 'not_found' });
    usaService.fetchGeoSnapshots.mockResolvedValue({ status: 'not_found' });
    usaService.fetchDisasterSpending.mockResolvedValue({ status: 'not_found' });
    femaService.fetchDeclarationsByState.mockResolvedValue([]);

    if (agencyFetchResult) usaService.fetchAgencies.mockResolvedValue(agencyFetchResult);
    if (spendingFetchResult) usaService.fetchSpendingByAgency.mockResolvedValue(spendingFetchResult);
    if (geoFetchResult) usaService.fetchGeoSnapshots.mockResolvedValue(geoFetchResult);
    if (disasterFetchResult) usaService.fetchDisasterSpending.mockResolvedValue(disasterFetchResult);
    if (femaFetchResult) femaService.fetchDeclarationsByState.mockResolvedValue(femaFetchResult);

    agencyRepo.findOne.mockImplementation(async ({ where }: any) => {
      if (where?.toptierCode) return findOneReturns.Agency ?? null;
      return null;
    });
    spendingRepo.findOne.mockImplementation(async ({ where }: any) => {
      if (where?.agencyId && where?.fiscalYear && where?.quarter && where?.awardTypeLabel) {
        return findOneReturns.SpendingRecord ?? null;
      }
      return null;
    });
    geoRepo.findOne.mockImplementation(async ({ where }: any) => {
      if (where?.stateCode && where?.fiscalYear) {
        return findOneReturns.GeoSpendingSnapshot ?? null;
      }
      return null;
    });
    disasterRepo.findOne.mockImplementation(async ({ where }: any) => {
      if (where?.defGroup && where?.stateCode) {
        return findOneReturns.DisasterFundingRecord ?? null;
      }
      return null;
    });

    await (service as Record<string, unknown>)[method]();

    for (const call of expectedSaveCalls) {
      const repo = getRepo(call.repoName);
      const saveCalls = (repo.save as jest.Mock).mock.calls;
      expect(saveCalls.length).toBe(call.count);
    }

    if (expectedRepoData) {
      for (const [repoName, expectedData] of Object.entries(expectedRepoData)) {
        const repo = getRepo(repoName);
        const saveCalls = (repo.save as jest.Mock).mock.calls;
        for (let i = 0; i < saveCalls.length; i++) {
          const saved = saveCalls[i][0];
          const expected = (expectedData as any[])[i];
          for (const [key, value] of Object.entries(expected)) {
            expect(saved[key]).toBe(value);
          }
        }
      }
    }
  });

  function getRepo(name: string): { save: jest.Mock } {
    switch (name) {
      case 'agency': return { save: agencyRepo.save };
      case 'spending': return { save: spendingRepo.save };
      case 'geo': return { save: geoRepo.save };
      case 'disaster': return { save: disasterRepo.save };
      case 'ratio': return { save: ratioRepo.save };
    }
  }
});

import { ComponentFixture, TestBed } from '@angular/core/testing';
import { HttpClientTestingModule } from '@angular/common/http/testing';
import { of } from 'rxjs';
import { DisasterLensComponent } from './disaster-lens.component';
import { ApiService } from '../api.service';
import { CurrencyFormatPipe } from '../currency-format.pipe';
import {
  DisasterFundingRecord,
  DisasterOverview,
  DisasterRecoveryRatio,
} from '@shared/interfaces';

describe('DisasterLensComponent', () => {
  let component: DisasterLensComponent;
  let fixture: ComponentFixture<DisasterLensComponent>;
  let apiSpy: {
    getDisasterOverview: jest.Mock;
    getDisasterStates: jest.Mock;
    getDisasterRecoveryRatios: jest.Mock;
  };

  beforeEach(async () => {
    apiSpy = {
      getDisasterOverview: jest.fn(),
      getDisasterStates: jest.fn(),
      getDisasterRecoveryRatios: jest.fn(),
    };

    await TestBed.configureTestingModule({
      imports: [
        DisasterLensComponent,
        CurrencyFormatPipe,
        HttpClientTestingModule,
      ],
      providers: [{ provide: ApiService, useValue: apiSpy }],
    }).compileComponents();

    fixture = TestBed.createComponent(DisasterLensComponent);
    component = fixture.componentInstance;
    component.paginator = { pageIndex: 0, pageSize: 15, length: 0 } as any;
  });

  interface CardTestCase {
    name: string;
    currentTab?: string;
    overview: DisasterOverview[];
    states: DisasterFundingRecord[];
    ratios: DisasterRecoveryRatio[];
    expectedTotalObligated: number;
    expectedStateCount: number;
    expectedGapCount: number;
    expectedHighestPerCapitaState: string;
  }

  const testTable: CardTestCase[] = [
    {
      name: 'computes totals from single overview entry with states',
      overview: [{
        defGroup: 'COVID-19',
        totalObligated: 500000,
        totalAwardCount: 100,
        stateCount: 2,
        highestPerCapitaState: 'CA',
        highestPerCapita: 100000,
        coverageGapCount: 0,
      }],
      states: [
        {
          id: 1, stateCode: 'CA', stateName: 'California',
          obligatedAmount: 300000, awardCount: 50,
          perCapita: 0, population: 0, defGroup: 'COVID-19', defCodes: '',
        },
        {
          id: 2, stateCode: 'NY', stateName: 'New York',
          obligatedAmount: 200000, awardCount: 50,
          perCapita: 0, population: 0, defGroup: 'COVID-19', defCodes: '',
        },
      ],
      ratios: [],
      expectedTotalObligated: 500000,
      expectedStateCount: 2,
      expectedGapCount: 0,
      expectedHighestPerCapitaState: 'CA',
    },
    {
      name: 'returns zero values when no overview data',
      overview: [],
      states: [],
      ratios: [],
      expectedTotalObligated: 0,
      expectedStateCount: 0,
      expectedGapCount: 0,
      expectedHighestPerCapitaState: '',
    },
    {
      name: 'counts coverage gaps from recovery ratios below 0.5',
      overview: [{
        defGroup: 'COVID-19',
        totalObligated: 1000000,
        totalAwardCount: 200,
        stateCount: 3,
        highestPerCapitaState: 'FL',
        highestPerCapita: 500000,
        coverageGapCount: 0,
      }],
      states: [
        {
          id: 3, stateCode: 'FL', stateName: 'Florida',
          obligatedAmount: 500000, awardCount: 100,
          perCapita: 0, population: 0, defGroup: 'Hurricane', defCodes: '',
        },
        {
          id: 4, stateCode: 'GA', stateName: 'Georgia',
          obligatedAmount: 300000, awardCount: 60,
          perCapita: 0, population: 0, defGroup: 'Hurricane', defCodes: '',
        },
        {
          id: 5, stateCode: 'AL', stateName: 'Alabama',
          obligatedAmount: 200000, awardCount: 40,
          perCapita: 0, population: 0, defGroup: 'Hurricane', defCodes: '',
        },
      ],
      ratios: [
        {
          id: 1, stateCode: 'FL', stateName: 'Florida', fiscalYear: 2024,
          femaObligated: 100000, fedSpendingObligated: 500000,
          declarationCount: 3, recoveryRatio: 5.0, dominantIncidentType: 'Hurricane',
        },
        {
          id: 2, stateCode: 'GA', stateName: 'Georgia', fiscalYear: 2024,
          femaObligated: 100000, fedSpendingObligated: 20000,
          declarationCount: 2, recoveryRatio: 0.2, dominantIncidentType: 'Hurricane',
        },
        {
          id: 3, stateCode: 'AL', stateName: 'Alabama', fiscalYear: 2024,
          femaObligated: 50000, fedSpendingObligated: 25000,
          declarationCount: 1, recoveryRatio: 0.5, dominantIncidentType: 'Hurricane',
        },
      ],
      expectedTotalObligated: 1000000,
      expectedStateCount: 3,
      expectedGapCount: 1,
      expectedHighestPerCapitaState: 'FL',
    },
    {
      name: 'handles multiple overview entries using current tab',
      overview: [
        {
          defGroup: 'COVID-19',
          totalObligated: 100000,
          totalAwardCount: 50,
          stateCount: 1,
          highestPerCapitaState: 'TX',
          highestPerCapita: 80000,
          coverageGapCount: 0,
        },
        {
          defGroup: 'Wildfire',
          totalObligated: 200000,
          totalAwardCount: 80,
          stateCount: 2,
          highestPerCapitaState: 'CA',
          highestPerCapita: 150000,
          coverageGapCount: 1,
        },
      ],
      states: [
        {
          id: 6, stateCode: 'TX', stateName: 'Texas',
          obligatedAmount: 100000, awardCount: 50,
          perCapita: 0, population: 0, defGroup: 'COVID-19', defCodes: '',
        },
      ],
      ratios: [],
      expectedTotalObligated: 100000,
      expectedStateCount: 1,
      expectedGapCount: 0,
      expectedHighestPerCapitaState: 'TX',
    },
    {
      name: 'selects overview entry matching non-default tab',
      currentTab: 'Wildfire',
      overview: [
        {
          defGroup: 'COVID-19',
          totalObligated: 100000,
          totalAwardCount: 50,
          stateCount: 1,
          highestPerCapitaState: 'TX',
          highestPerCapita: 80000,
          coverageGapCount: 0,
        },
        {
          defGroup: 'Wildfire',
          totalObligated: 750000,
          totalAwardCount: 30,
          stateCount: 2,
          highestPerCapitaState: 'CA',
          highestPerCapita: 200000,
          coverageGapCount: 1,
        },
      ],
      states: [
        {
          id: 7, stateCode: 'CA', stateName: 'California',
          obligatedAmount: 500000, awardCount: 20,
          perCapita: 200000, population: 0, defGroup: 'Wildfire', defCodes: 'M',
        },
      ],
      ratios: [],
      expectedTotalObligated: 750000,
      expectedStateCount: 1,
      expectedGapCount: 0,
      expectedHighestPerCapitaState: 'CA',
    },
  ];

  it.each(testTable)('$name', async ({
    overview, states, ratios, currentTab,
    expectedTotalObligated, expectedStateCount, expectedGapCount, expectedHighestPerCapitaState,
  }) => {
    apiSpy.getDisasterOverview.mockReturnValue(of(overview));
    apiSpy.getDisasterStates.mockReturnValue(of(states));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of(ratios));

    component.currentTab = currentTab ?? 'COVID-19';
    component.ngOnInit();
    await fixture.whenStable();
    fixture.detectChanges();

    expect(component.totalObligated).toBe(expectedTotalObligated);
    expect(component.stateCount).toBe(expectedStateCount);
    expect(component.coverageGapCount).toBe(expectedGapCount);
    expect(component.highestPerCapitaState).toBe(expectedHighestPerCapitaState);
  });

  interface Top15TestCase {
    name: string;
    states: DisasterFundingRecord[];
    expectedLabels: string[];
    expectedDataset: number[];
  }

  const testTableTop15: Top15TestCase[] = [
    {
      name: 'returns top 15 states by obligatedAmount descending',
      states: Array.from({ length: 20 }, (_, i) => ({
        id: i + 1, stateCode: `ST${String(i + 1).padStart(2, '0')}`, stateName: `State ${String(i + 1)}`,
        obligatedAmount: (20 - i) * 100000, awardCount: 0,
        perCapita: 0, population: 0, defGroup: 'COVID-19', defCodes: '',
      })),
      expectedLabels: Array.from({ length: 15 }, (_, i) => `State ${String(i + 1)}`),
      expectedDataset: Array.from({ length: 15 }, (_, i) => (20 - i) * 100000),
    },
    {
      name: 'returns fewer than 15 when less than 15 states exist',
      states: [
        { id: 1, stateCode: 'CA', stateName: 'California', obligatedAmount: 300000, awardCount: 0, perCapita: 0, population: 0, defGroup: 'COVID-19', defCodes: '' },
        { id: 2, stateCode: 'NY', stateName: 'New York', obligatedAmount: 200000, awardCount: 0, perCapita: 0, population: 0, defGroup: 'COVID-19', defCodes: '' },
        { id: 3, stateCode: 'TX', stateName: 'Texas', obligatedAmount: 150000, awardCount: 0, perCapita: 0, population: 0, defGroup: 'COVID-19', defCodes: '' },
      ],
      expectedLabels: ['California', 'New York', 'Texas'],
      expectedDataset: [300000, 200000, 150000],
    },
    {
      name: 'returns empty arrays when no states data',
      states: [],
      expectedLabels: [],
      expectedDataset: [],
    },
  ];

  it.each(testTableTop15)('$name', async ({
    states, expectedLabels, expectedDataset,
  }) => {
    apiSpy.getDisasterOverview.mockReturnValue(of([]));
    apiSpy.getDisasterStates.mockReturnValue(of(states));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));

    component.ngOnInit();
    await fixture.whenStable();
    fixture.detectChanges();

    expect(component.top15Labels).toEqual(expectedLabels);
    expect(component.top15Datasets).toEqual(expectedDataset);
  });

  interface SortedRatiosTestCase {
    name: string;
    ratios: DisasterRecoveryRatio[];
    expectedOrder: string[];
  }

  const testTableSortedRatios: SortedRatiosTestCase[] = [
    {
      name: 'sorts ratios ascending by recoveryRatio',
      ratios: [
        { id: 1, stateCode: 'CA', stateName: 'California', fiscalYear: 2024, femaObligated: 100000, fedSpendingObligated: 500000, declarationCount: 3, recoveryRatio: 5.0, dominantIncidentType: 'Wildfire' },
        { id: 2, stateCode: 'FL', stateName: 'Florida', fiscalYear: 2024, femaObligated: 100000, fedSpendingObligated: 20000, declarationCount: 2, recoveryRatio: 0.2, dominantIncidentType: 'Hurricane' },
        { id: 3, stateCode: 'NY', stateName: 'New York', fiscalYear: 2024, femaObligated: 50000, fedSpendingObligated: 25000, declarationCount: 1, recoveryRatio: 0.5, dominantIncidentType: 'Hurricane' },
      ],
      expectedOrder: ['Florida', 'New York', 'California'],
    },
    {
      name: 'handles empty ratios array',
      ratios: [],
      expectedOrder: [],
    },
    {
      name: 'handles single ratio',
      ratios: [
        { id: 1, stateCode: 'TX', stateName: 'Texas', fiscalYear: 2024, femaObligated: 100000, fedSpendingObligated: 100000, declarationCount: 1, recoveryRatio: 1.0, dominantIncidentType: 'Infrastructure' },
      ],
      expectedOrder: ['Texas'],
    },
  ];

  it.each(testTableSortedRatios)('$name', async ({ ratios, expectedOrder }) => {
    apiSpy.getDisasterOverview.mockReturnValue(of([]));
    apiSpy.getDisasterStates.mockReturnValue(of([]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of(ratios));

    component.ngOnInit();
    await fixture.whenStable();
    fixture.detectChanges();

    expect(component.sortedRatios.map((r) => r.stateName)).toEqual(expectedOrder);
  });
});
